import anthropic

client = anthropic.Anthropic()

# Tight max_tokens for classification tasks — no wasted output
def classify_sentiment(text: str) -> str:
    response = client.messages.create(
        model="claude-haiku-4-5",   # smallest model for simple task
        max_tokens=5,               # "positive", "negative", or "neutral"
        system="Reply with exactly one word: positive, negative, or neutral.",
        messages=[{"role": "user", "content": text}],
    )
    return response.content[0].text.strip()

# For longer tasks, stream to minimize perceived latency
def summarize_streaming(document: str):
    with client.messages.stream(
        model="claude-sonnet-4-6",
        max_tokens=512,
        messages=[{"role": "user", "content": f"Summarize:\n\n{document}"}],
    ) as stream:
        for text in stream.text_stream:
            yield text  # caller can display tokens as they arrive

import anthropic

client = anthropic.Anthropic()

SIMPLE_TASKS = {"classify", "summarize", "extract"}
COMPLEX_TASKS = {"reason", "code", "analyze"}

def route_to_model(task_type: str, prompt: str) -> str:
    if task_type in SIMPLE_TASKS:
        model = "claude-haiku-4-5"
    elif task_type in COMPLEX_TASKS:
        model = "claude-opus-4-8"
    else:
        model = "claude-sonnet-4-6"  # default: balanced

    response = client.messages.create(
        model=model,
        max_tokens=1024,
        messages=[{"role": "user", "content": prompt}],
    )
    return response.content[0].text

import anthropic, time

client = anthropic.Anthropic()

def compare_thinking_latency(problem: str):
    for thinking in [False, True]:
        kwargs = {"model": "claude-opus-4-8", "max_tokens": 16000, "messages": [{"role": "user", "content": problem}]}
        if thinking:
            kwargs["thinking"] = {"type": "enabled", "budget_tokens": 5000}
        start = time.perf_counter()
        response = client.messages.create(**kwargs)
        elapsed = time.perf_counter() - start
        print(f"thinking={'on' if thinking else 'off'}: {elapsed:.1f}s, {response.usage.output_tokens} output tokens")

compare_thinking_latency("What is 17 * 23?")
compare_thinking_latency("Prove that sqrt(2) is irrational.")

import anthropic, time, statistics

client = anthropic.Anthropic()

def benchmark_latency(prompt: str, model: str, n_samples: int = 20) -> dict:
    ttft_samples = []
    total_samples = []

    for _ in range(n_samples):
        start = time.perf_counter()
        first_token_time = None

        with client.messages.stream(
            model=model,
            max_tokens=256,
            messages=[{"role": "user", "content": prompt}],
        ) as stream:
            for _ in stream.text_stream:
                if first_token_time is None:
                    first_token_time = time.perf_counter() - start
                    break  # stop after first token for TTFT

        total_time = time.perf_counter() - start  # includes all tokens
        if first_token_time:
            ttft_samples.append(first_token_time)
        total_samples.append(total_time)

    def stats(samples):
        s = sorted(samples)
        return {
            "p50": round(statistics.median(s), 3),
            "p95": round(s[int(len(s)*0.95)], 3),
            "p99": round(s[int(len(s)*0.99)], 3),
        }

    return {"ttft": stats(ttft_samples), "total": stats(total_samples)}

result = benchmark_latency("Summarize AI in one sentence.", "claude-haiku-4-5")
print("TTFT (s):", result["ttft"])
print("Total (s):", result["total"])
